1	<script lang="ts">
2		import type { LayoutData } from './$types';
3		import type { Snippet } from 'svelte';
4		import { goto, invalidateAll } from '$app/navigation';
5		import { page } from '$app/stores';
6		import { createClient } from '$lib/gql/client';
7		import { subscribeWorkerProgress } from '$lib/gql/subscriptions';
8		import { gql } from 'graphql-request';
9	
10		let { data, children }: { data: LayoutData; children: Snippet } = $props();
11	
12		const START_WORKER_MUTATION = gql`
13			mutation StartWorker($input: StartWorkerInput!) {
14				startWorker(input: $input) {
15					id
16					state
17					kind
18				}
19			}
20		`;
21	
22		const STOP_WORKER_MUTATION = gql`
23			mutation StopWorker($id: ID!) {
24				stopWorker(id: $id) {
25					id
26					state
27					kind
28				}
29			}
30		`;
31	
32		// + Add worker dispatches a default-spec drain worker (ddx-b6cf025c). The
33		// server honours .ddx/config.yaml workers.default_spec + workers.max_count.
34		const ADD_WORKER_MUTATION = gql`
35			mutation AddDrainWorker($projectId: String!) {
36				workerDispatch(kind: "work", projectId: $projectId) {
37					id
38					state
39					kind
40				}
41			}
42		`;
43	
44		// Live phase overrides from workerProgress subscription (workerID -> phase)
45		let livePhaseOverrides = $state<Map<string, string>>(new Map());
46		let showStartForm = $state(false);
47		let starting = $state(false);
48		let stoppingId = $state<string | null>(null);
49		let actionError = $state<string | null>(null);
50		let harness = $state('');
51		let profile = $state('smart');
52		let effort = $state('medium');
53		let labelFilter = $state('');
54		let adding = $state(false);
55		let removing = $state(false);
56	
57		// Drain workers: count of running work workers.
58		const runningDrainCount = $derived(
59			data.workers.edges.filter(
60				(e) => e.node.state === 'running' && e.node.kind === 'work'
61			).length
62		);
63	
64		// workers.max_count safety rail (ddx-b6cf025c). Null = no cap configured.
65		const maxCount = $derived(data.maxCount);
66		const atMaxCount = $derived(
67			typeof maxCount === 'number' && maxCount >= 0 && runningDrainCount >= maxCount
68		);
69		const addDisabled = $derived(adding || atMaxCount);
70		const addTooltip = $derived(
71			atMaxCount ? 'at workers.max_count limit' : 'Add a general-purpose drain worker'
72		);
73	
74		// Subscribe to progress events for all running workers
75		$effect(() => {
76			const runningIds = data.workers.edges
77				.filter((e) => e.node.state === 'running')
78				.map((e) => e.node.id);
79	
80			livePhaseOverrides = new Map();
81	
82			const disposes = runningIds.map((workerID) =>
83				subscribeWorkerProgress(workerID, (evt) => {
84					const next = new Map(livePhaseOverrides);
85					next.set(evt.workerID, evt.phase);
86					livePhaseOverrides = next;
87				})
88			);
89	
90			return () => disposes.forEach((d) => d());
91		});
92	
93		// The currently open worker (from child route params)
94		let activeWorker = $derived(($page.params as Record<string, string>)['workerId'] ?? null);
95	
96		function openWorker(workerId: string) {
97			const p = $page.params as Record<string, string>;
98			goto(`/nodes/${p['nodeId']}/projects/${p['projectId']}/workers/${workerId}`);
99		}
100	
101		function sessionsHref(): string {
102			const p = $page.params as Record<string, string>;
103			return `/nodes/${p['nodeId']}/projects/${p['projectId']}/runs?layer=run`;
104		}
105	
106		function providerHref(name: string): string {
107			const p = $page.params as Record<string, string>;
108			return `/nodes/${p['nodeId']}/providers/${encodeURIComponent(name)}`;
109		}
110	
111		function errorText(err: unknown): string {
112			return err instanceof Error ? err.message : 'Worker action failed.';
113		}
114	
115		async function startWorker() {
116			actionError = null;
117			if (!profile.trim() || !effort.trim()) {
118				actionError = 'Profile and effort are required.';
119				return;
120			}
121			starting = true;
122			try {
123				const client = createClient(fetch);
124				await client.request(START_WORKER_MUTATION, {
125					input: {
126						projectId: data.projectId,
127						harness: harness.trim() || null,
128						profile: profile.trim(),
129						effort: effort.trim(),
130						labelFilter: labelFilter.trim() || null
131					}
132				});
133				showStartForm = false;
134				harness = '';
135				labelFilter = '';
136				await invalidateAll();
137			} catch (err) {
138				actionError = errorText(err);
139			} finally {
140				starting = false;
141			}
142		}
143	
144		async function addDrainWorker() {
145			actionError = null;
146			adding = true;
147			try {
148				const client = createClient(fetch);
149				await client.request(ADD_WORKER_MUTATION, { projectId: data.projectId });
150				await invalidateAll();
151			} catch (err) {
152				actionError = errorText(err);
153			} finally {
154				adding = false;
155			}
156		}
157	
158		async function removeDrainWorker() {
159			actionError = null;
160			// Find the oldest running work worker (AC #4: "stops the oldest-
161			// running drain worker"). data.workers is sorted newest-first, so the
162			// last matching edge is oldest.
163			const runningDrain = data.workers.edges
164				.filter((e) => e.node.state === 'running' && e.node.kind === 'work')
165				.map((e) => e.node);
166			const target = runningDrain[runningDrain.length - 1];
167			if (!target) return;
168			if (!window.confirm(`Stop worker ${target.id}?`)) return;
169			removing = true;
170			try {
171				const client = createClient(fetch);
172				await client.request(STOP_WORKER_MUTATION, { id: target.id });
173				await invalidateAll();
174			} catch (err) {
175				actionError = errorText(err);
176			} finally {
177				removing = false;
178			}
179		}
180	
181		async function stopWorker(event: MouseEvent, workerId: string) {
182			event.stopPropagation();
183			actionError = null;
184			if (!window.confirm(`Stop worker ${workerId}?`)) return;
185			stoppingId = workerId;
186			try {
187				const client = createClient(fetch);
188				await client.request(STOP_WORKER_MUTATION, { id: workerId });
189				await invalidateAll();
190			} catch (err) {
191				actionError = errorText(err);
192			} finally {
193				stoppingId = null;
194			}
195		}
196	
197		function stateClass(state: string): string {
198			switch (state) {
199				case 'running':
200					return 'text-status-running';
201				case 'idle':
202					return 'text-status-open';
203				case 'stopped':
204					return 'text-fg-muted dark:text-dark-fg-muted';
205				case 'error':
206					return 'text-status-failed';
207				default:
208					return 'text-fg-muted dark:text-dark-fg-muted';
209			}
210		}
211	
212		// ADR-022 step 5b: freshness badge classes for reported (derived-view)
213		// workers. The state strings come from the server (connected | stale |
214		// disconnected) — see ReportedWorker.state in schema.graphql.
215		function freshnessBadgeClass(state: string): string {
216			switch (state) {
217				case 'connected':
218					return 'border-status-running bg-status-running/10 text-status-running';
219				case 'stale':
220					return 'border-status-open bg-status-open/10 text-status-open';
221				case 'disconnected':
222					return 'border-status-failed bg-status-failed/10 text-status-failed';
223				default:
224					return 'border-border-line bg-bg-surface text-fg-muted dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-muted';
225			}
226		}
227	
228		function formatTimestamp(iso: string): string {
229			try {
230				return new Date(iso).toLocaleString();
231			} catch {
232				return iso;
233			}
234		}
235	
236		// Group reported workers by project root so duplicates (same project, two
237		// worker_ids) render distinctly per ADR-022 §worker-server-interface
238		// (multiple workers per project root is expected and visible).
239		const reportedByProject = $derived.by(() => {
240			const groups = new Map<string, typeof data.reportedWorkers>();
241			for (const rw of data.reportedWorkers ?? []) {
242				const key = rw.project || '(unknown)';
243				const list = groups.get(key) ?? [];
244				list.push(rw);
245				groups.set(key, list);
246			}
247			return Array.from(groups.entries()).map(([project, workers]) => ({ project, workers }));
248		});
249	</script>
250	
251	<div class="space-y-4">
252		<!-- Drain-worker count control (ddx-b6cf025c). Dispatches a default-spec
253		     worker; server enforces workers.default_spec + workers.max_count. -->
254		<div
255			data-testid="drain-count-panel"
256			class="flex flex-col gap-3 border border-border-line bg-bg-surface p-4 text-body-sm dark:border-dark-border-line dark:bg-dark-bg-surface sm:flex-row sm:items-center sm:justify-between"
257		>
258			<div>
259				<div class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">
260					Drain workers
261				</div>
262				<div
263					data-testid="drain-worker-count"
264					class="mt-1 text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink"
265				>
266					{runningDrainCount}
267				</div>
268				<p class="mt-1 text-body-sm text-fg-muted dark:text-dark-fg-muted">
269					Adds a general-purpose drain worker. Use the per-harness picker below for custom specs.
270				</p>
271			</div>
272			<div class="flex items-center gap-2">
273				<button
274					type="button"
275					data-testid="add-drain-worker"
276					onclick={() => void addDrainWorker()}
277					disabled={addDisabled}
278					title={addTooltip}
279					class="border border-accent-lever bg-accent-lever px-3 py-1.5 text-body-sm font-medium text-white hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-accent-lever dark:bg-dark-accent-lever"
280					aria-label="Add worker"
281				>
282					{adding ? '…' : '+ Add worker'}
283				</button>
284				<button
285					type="button"
286					data-testid="remove-drain-worker"
287					onclick={() => void removeDrainWorker()}
288					disabled={removing || runningDrainCount === 0}
289					class="border border-border-line px-3 py-1.5 text-body-sm font-medium text-error hover:bg-bg-canvas disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-border-line dark:text-dark-error dark:hover:bg-dark-bg-surface"
290					aria-label="Remove worker"
291				>
292					{removing ? '…' : '− Remove worker'}
293				</button>
294			</div>
295		</div>
296	
297		<div class="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
298			<div>
299				<h1 class="text-headline-lg font-headline-lg text-fg-ink dark:text-dark-fg-ink">Workers</h1>
300				<p class="mt-1 max-w-2xl text-body-sm text-fg-muted dark:text-dark-fg-muted">
301					Workers drain the bead queue as long-lived processes; Sessions are the history of
302					what they ran.
303				</p>
304				<a class="mt-2 inline-flex text-body-sm text-accent-lever hover:underline dark:text-dark-accent-lever" href={sessionsHref()}>
305					Recent sessions →
306				</a>
307			</div>
308			<div class="flex items-center gap-3">
309				<span class="text-body-sm text-fg-muted dark:text-dark-fg-muted">
310					{data.workers.totalCount} total
311				</span>
312				<button
313					type="button"
314					onclick={() => {
315						actionError = null;
316						showStartForm = !showStartForm;
317					}}
318					class="border border-accent-lever bg-accent-lever px-3 py-1.5 text-body-sm font-medium text-white hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-accent-lever dark:bg-dark-accent-lever"
319				>
320					Start worker
321				</button>
322			</div>
323		</div>
324	
325		{#if showStartForm}
326			<form
327				class="grid gap-3 border border-border-line bg-bg-surface p-4 text-body-sm dark:border-dark-border-line dark:bg-dark-bg-surface sm:grid-cols-4"
328				onsubmit={(event) => {
329					event.preventDefault();
330					void startWorker();
331				}}
332			>
333				<label class="space-y-1">
334					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Harness</span>
335					<input
336						bind:value={harness}
337						placeholder="auto"
338						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
339					/>
340				</label>
341				<label class="space-y-1">
342					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Profile</span>
343					<select
344						bind:value={profile}
345						required
346						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
347					>
348						<option value="cheap">cheap</option>
349						<option value="fast">fast</option>
350						<option value="smart">smart</option>
351					</select>
352				</label>
353				<label class="space-y-1">
354					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Effort</span>
355					<select
356						bind:value={effort}
357						required
358						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
359					>
360						<option value="low">low</option>
361						<option value="medium">medium</option>
362						<option value="high">high</option>
363					</select>
364				</label>
365				<label class="space-y-1">
366					<span class="text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Label filter</span>
367					<input
368						bind:value={labelFilter}
369						placeholder="optional"
370						class="w-full border border-border-line bg-bg-elevated px-2 py-1.5 text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink"
371					/>
372				</label>
373				<div class="flex items-end gap-2 sm:col-span-4">
374					<button
375						type="submit"
376						disabled={starting || !profile.trim() || !effort.trim()}
377						class="border border-fg-ink bg-fg-ink px-3 py-1.5 text-body-sm font-medium text-bg-canvas hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-fg-ink dark:bg-dark-fg-ink dark:text-dark-bg-canvas"
378					>
379						{starting ? 'Starting…' : 'Start'}
380					</button>
381					<button
382						type="button"
383						onclick={() => (showStartForm = false)}
384						class="px-3 py-1.5 text-body-sm text-fg-muted hover:bg-bg-canvas dark:text-dark-fg-muted dark:hover:bg-dark-bg-surface"
385					>
386						Cancel
387					</button>
388				</div>
389			</form>
390		{/if}
391	
392		{#if actionError}
393			<div class="border border-border-line bg-bg-surface px-3 py-2 text-body-sm text-status-failed dark:border-dark-border-line dark:bg-dark-bg-surface">
394				{actionError}
395			</div>
396		{/if}
397	
398		<div class="overflow-hidden border border-border-line dark:border-dark-border-line">
399			<table class="w-full text-body-sm">
400				<thead>
401					<tr class="border-b border-border-line bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface">
402						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">ID</th>
403						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Kind</th>
404						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
405							>State / Phase</th
406						>
407						<th class="px-4 py-3 text-left text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
408							>Current Bead</th
409						>
410						<th class="px-4 py-3 text-right text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted"
411							>Attempts</th
412						>
413						<th class="px-4 py-3 text-right text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:text-dark-fg-muted">Actions</th>
414					</tr>
415				</thead>
416				<tbody>
417					{#each data.workers.edges as edge (edge.cursor)}
418						<tr
419							onclick={() => openWorker(edge.node.id)}
420							class="cursor-pointer border-b border-border-line last:border-0 hover:bg-bg-surface dark:border-dark-border-line dark:hover:bg-dark-bg-surface {activeWorker ===
421							edge.node.id
422								? 'bg-accent-lever/10 dark:bg-dark-accent-lever/10'
423								: ''}"
424						>
425							<td class="px-4 py-3 font-mono-code text-mono-code text-accent-lever dark:text-dark-accent-lever">
426								{edge.node.id.slice(0, 8)}
427							</td>
428							<td class="px-4 py-3 text-fg-ink dark:text-dark-fg-ink">
429								<div class="space-y-1">
430									<div>{edge.node.kind}</div>
431									{#if edge.node.harness}
432										<a
433											href={providerHref(edge.node.harness)}
434											onclick={(event) => event.stopPropagation()}
435											class="text-body-sm text-accent-lever hover:underline dark:text-dark-accent-lever"
436											data-testid="worker-provider-link-{edge.node.id}"
437										>
438											{edge.node.harness}
439										</a>
440									{/if}
441								</div>
442							</td>
443							<td class="px-4 py-3">
444								<span
445									class="font-medium {stateClass(
446										livePhaseOverrides.get(edge.node.id) ?? edge.node.state
447									)}"
448								>
449									{livePhaseOverrides.get(edge.node.id) ?? edge.node.state}
450								</span>
451							</td>
452							<td class="px-4 py-3 font-mono-code text-mono-code text-fg-muted dark:text-dark-fg-muted">
453								{edge.node.currentBead ?? '—'}
454							</td>
455							<td class="px-4 py-3 text-right text-fg-muted dark:text-dark-fg-muted">
456								{#if edge.node.attempts != null}
457									<span title="{edge.node.successes ?? 0}✓ / {edge.node.failures ?? 0}✗">
458										{edge.node.attempts}
459									</span>
460								{:else}
461									—
462								{/if}
463							</td>
464							<td class="px-4 py-3 text-right">
465								{#if edge.node.state === 'running'}
466									<button
467										type="button"
468										onclick={(event) => stopWorker(event, edge.node.id)}
469										disabled={stoppingId === edge.node.id}
470										class="border border-border-line px-2 py-1 text-xs font-medium text-status-failed hover:bg-bg-canvas disabled:cursor-not-allowed disabled:opacity-60 dark:border-dark-border-line dark:hover:bg-dark-bg-surface"
471									>
472										{stoppingId === edge.node.id ? 'Stopping…' : 'Stop'}
473									</button>
474								{:else}
475									<span class="text-mono-code text-fg-muted dark:text-dark-fg-muted">—</span>
476								{/if}
477							</td>
478						</tr>
479					{/each}
480					{#if data.workers.edges.length === 0}
481						<tr>
482							<td colspan="6" class="px-4 py-8 text-center text-body-sm text-fg-muted dark:text-dark-fg-muted">
483								No workers found. Nothing is draining this queue right now; start a worker here
484								or run ddx work from a terminal.
485							</td>
486						</tr>
487					{/if}
488				</tbody>
489			</table>
490		</div>
491	
492		<!--
493			ADR-022 step 5b: reported-workers panel surfaces the worker_ingest
494			derived view (trusted-peer reports). Distinct from the in-process
495			workers table above: this view is best-effort, possibly stale, and
496			labeled non-authoritative so operators don't conflate it with the
497			registry of locally-managed workers.
498		-->
499		<section
500			data-testid="reported-workers-panel"
501			class="space-y-3 border border-border-line bg-bg-surface p-4 dark:border-dark-border-line dark:bg-dark-bg-surface"
502		>
503			<header class="flex flex-col gap-1">
504				<div class="flex items-center gap-2">
505					<h2 class="text-headline-md font-headline-md text-fg-ink dark:text-dark-fg-ink">
506						Reported workers
507					</h2>
508					<span
509						data-testid="reported-not-authoritative"
510						class="border border-border-line px-2 py-0.5 text-label-caps font-label-caps uppercase tracking-wide text-fg-muted dark:border-dark-border-line dark:text-dark-fg-muted"
511						title="Server-derived from worker-reported events; may lag"
512					>
513						reported by worker (not authoritative)
514					</span>
515				</div>
516				<p class="max-w-2xl text-body-sm text-fg-muted dark:text-dark-fg-muted">
517					Trusted-peer worker reports for project root
518					<span class="font-mono-code text-mono-code">{data.projectPath ?? '(unknown)'}</span>.
519					Multiple entries under one project root are expected when two workers run concurrently.
520				</p>
521			</header>
522	
523			{#if (data.reportedWorkers ?? []).length === 0}
524				<p
525					data-testid="reported-workers-empty"
