158		async function removeDrainWorker() {
159			actionError = null;
160			// Find the oldest running work worker (AC #4: "stops the oldest-
161			// running drain worker"). data.workers is sorted newest-first, so the
162			// last matching edge is oldest.
163			const runningDrain = data.workers.edges
164				.filter((e) => e.node.state === 'running' && e.node.kind === 'work')
165				.map((e) => e.node);
