197		function stateClass(state: string): string {
198			switch (state) {
199				case 'running':
200					return 'text-status-running';
201				case 'idle':
202					return 'text-status-open';
203				case 'stopped':
204					return 'text-fg-muted dark:text-dark-fg-muted';
205				case 'error':
