import type { LayoutLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

const NODE_WORKERS_QUERY = gql`
	query NodeWideWorkers($first: Int) {
		workers(first: $first) {
			edges {
				node {
					id
					kind
					state
					status
					harness
					model
					projectRoot
					currentBead
					attempts
					successes
					failures
					startedAt
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

const FEDERATED_WORKERS_QUERY = gql`
	query FederatedNodeWorkers($first: Int) {
		workers(first: $first) {
			edges {
				node {
					id
					kind
					state
					status
					harness
					model
					currentBead
					attempts
					successes
					failures
					startedAt
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
	}
`

const PROJECTS_QUERY = gql`
	query ProjectsForWorkerPane {
		projects {
			edges {
				node {
					id
					name
					path
				}
			}
		}
	}
`

export interface WorkerNode {
	id: string
	kind: string
	state: string
	status: string | null
	harness: string | null
	model: string | null
	projectRoot?: string | null
	currentBead: string | null
	attempts: number | null
	successes: number | null
	failures: number | null
	startedAt: string | null
	// Optional fields that may be present in mocked or extended responses
	projectId?: string | null
	projectName?: string | null
	nodeName?: string | null
	nodeId?: string | null
}

export interface WorkerEdge {
	node: WorkerNode
	cursor: string
}

export interface WorkerConnection {
	edges: WorkerEdge[]
	pageInfo: { hasNextPage: boolean; endCursor: string | null }
	totalCount: number
}

interface WorkersResult {
	workers: WorkerConnection
}

interface ProjectNode {
	id: string
	name: string
	path: string
}

interface ProjectsResult {
	projects: {
		edges: Array<{ node: ProjectNode }>
	}
}

export const load: LayoutLoad = async ({ params, url, fetch }) => {
	const scope = url.searchParams.get('scope') === 'federation' ? 'federation' : 'local'
	const client = createClient(fetch as unknown as typeof globalThis.fetch)

	if (scope === 'federation') {
		const data = await client
			.request<WorkersResult>(FEDERATED_WORKERS_QUERY, { first: 100 })
			.catch(() => ({
				workers: {
					edges: [] as WorkerEdge[],
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: 0
				}
			}))
		return {
			nodeId: params.nodeId,
			workers: data.workers,
			scope: 'federation' as const,
			projectsByPath: {} as Record<string, { id: string; name: string }>
		}
	}

	const [workersData, projectsData] = await Promise.all([
		client
			.request<WorkersResult>(NODE_WORKERS_QUERY, { first: 100 })
			.catch(() => ({
				workers: {
					edges: [] as WorkerEdge[],
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: 0
				}
			})),
		client
			.request<ProjectsResult>(PROJECTS_QUERY)
			.catch(() => ({ projects: { edges: [] as Array<{ node: ProjectNode }> } }))
	])

	const projectsByPath: Record<string, { id: string; name: string }> = {}
	for (const { node } of projectsData.projects.edges) {
		if (node.path) {
			projectsByPath[node.path] = { id: node.id, name: node.name }
		}
	}

	return {
		nodeId: params.nodeId,
		workers: workersData.workers,
		scope: 'local' as const,
		projectsByPath
	}
}

import type { PageLoad } from './$types';
import { createClient } from '$lib/gql/client';
import { gql } from 'graphql-request';

const WORKER_QUERY = gql`
	query WorkerDetail($id: ID!) {
		worker(id: $id) {
			id
			kind
			state
			status
			harness
			model
			effort
			once
			pollInterval
			startedAt
			finishedAt
			currentBead
			lastError
			attempts
			successes
			failures
			currentAttempt {
				attemptId
				beadId
				phase
				startedAt
				elapsedMs
			}
			recentEvents {
				kind
				text
				name
				inputs
				output
			}
			lifecycleEvents {
				action
				actor
				timestamp
				detail
				beadId
			}
		}
	}
`;

const WORKER_LOG_QUERY = gql`
	query WorkerLog($workerID: ID!) {
		workerLog(workerID: $workerID) {
			stdout
			stderr
		}
	}
`;

interface CurrentAttempt {
	attemptId: string;
	beadId: string | null;
	phase: string;
	startedAt: string;
	elapsedMs: number;
}

export interface WorkerRecentEvent {
	kind: string;
	text: string | null;
	name: string | null;
	inputs: string | null;
	output: string | null;
}

export interface WorkerLifecycleEvent {
	action: string;
	actor: string;
	timestamp: string;
	detail: string | null;
	beadId: string | null;
}

export interface WorkerDetail {
	id: string;
	kind: string;
	state: string;
	status: string | null;
	harness: string | null;
	model: string | null;
	effort: string | null;
	once: boolean | null;
	pollInterval: string | null;
	startedAt: string | null;
	finishedAt: string | null;
	currentBead: string | null;
	lastError: string | null;
	attempts: number | null;
	successes: number | null;
	failures: number | null;
	currentAttempt: CurrentAttempt | null;
	recentEvents: WorkerRecentEvent[];
	lifecycleEvents: WorkerLifecycleEvent[];
}

interface WorkerResult {
	worker: WorkerDetail | null;
}

interface WorkerLogResult {
	workerLog: { stdout: string; stderr: string };
}

export const load: PageLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const [workerResult, logResult] = await Promise.all([
		client.request<WorkerResult>(WORKER_QUERY, { id: params.workerId }),
		client
			.request<WorkerLogResult>(WORKER_LOG_QUERY, { workerID: params.workerId })
			.catch(() => ({ workerLog: { stdout: '', stderr: '' } }))
	]);
	return {
		nodeId: params.nodeId,
		workerId: params.workerId,
		worker: workerResult.worker
			? {
					...workerResult.worker,
					recentEvents: workerResult.worker.recentEvents ?? [],
					lifecycleEvents: workerResult.worker.lifecycleEvents ?? []
				}
			: null,
		initialLog: logResult.workerLog.stdout
	};
};

