1	<script lang="ts">
2		import { onMount } from 'svelte';
3		import { goto } from '$app/navigation';
4		import { gql } from 'graphql-request';
5		import { createClient } from '$lib/gql/client';
6		import { nodeStore } from '$lib/stores/node.svelte';
7		import { projectStore } from '$lib/stores/project.svelte';
8	
9		const PROJECTS_QUERY = gql`
10			query Projects {
11				projects {
12					edges {
13						node {
14							id
15							name
16							path
17						}
18					}
19				}
20			}
21		`;
22	
23		interface ProjectNode {
24			id: string;
25			name: string;
26			path: string;
27		}
28	
29		interface ProjectsResult {
30			projects: {
31				edges: Array<{ node: ProjectNode }>;
32			};
33		}
34	
35		let projects = $state<ProjectNode[]>([]);
36		let loading = $state(true);
37	
38		onMount(async () => {
39			const client = createClient();
40			try {
41				const [data, current] = await Promise.all([
42					client.request<ProjectsResult>(PROJECTS_QUERY),
43					fetch('/api/projects/current')
44						.then((resp) => (resp.ok ? (resp.json() as Promise<ProjectNode>) : null))
45						.catch(() => null)
46				]);
47				projects = data.projects.edges.map((e) => e.node);
48				if (current) {
49					projects = [current, ...projects.filter((p) => p.id !== current.id)];
50				}
51				if (!projectStore.value && current) {
52					selectProject(current, false);
53				}
54			} finally {
55				loading = false;
56			}
57		});
58	
59		function selectProject(project: ProjectNode, navigate: boolean) {
60			projectStore.set({ id: project.id, name: project.name, path: project.path });
61	
62			const nodeId = nodeStore.value?.id;
63			if (navigate && nodeId) {
64				goto(`/nodes/${nodeId}/projects/${project.id}`);
65			}
66		}
67	
68		function handleChange(event: Event) {
69			const select = event.target as HTMLSelectElement;
70			const projectId = select.value;
71			if (!projectId) return;
72	
73			const project = projects.find((p) => p.id === projectId);
74			if (!project) return;
75	
76			selectProject(project, true);
77		}
78	</script>
