185			return `/executions/${encodeURIComponent(workerId)}/result.json`;
186		}
187	
188		function formatCompletedAt(value: string | null): string {
189			if (!value) return 'terminal state';
190			const date = new Date(value);
191			if (Number.isNaN(date.getTime())) return value;
192			return date.toLocaleTimeString([], {
193				hour: '2-digit',
194				minute: '2-digit',
195				second: '2-digit'
196			});
197		}
198	
199		function fmtDate(value: string): string {
200			const date = new Date(value);
201			if (Number.isNaN(date.getTime())) return value;
202			return date.toLocaleString();
203		}
204	
205		function fmtDuration(ms: number): string {
206			if (ms < 1000) return `${ms}ms`;
207			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
208			const m = Math.floor(ms / 60_000);
209			const s = Math.floor((ms % 60_000) / 1000);
210			return `${m}m ${s}s`;
211		}
212	
213		function fmtCost(cost: number | null): string {
214			return cost == null ? '—' : `$${cost.toFixed(4)}`;
215		}
216	
217		function sessionsHref(): string {
218			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs?layer=run`;
219		}
220	
221		const workerSessions = $derived(data.sessions ?? []);
222		const lifecycleEvents = $derived(data.worker?.lifecycleEvents ?? []);
223	
224		function appendLiveEvent(event: WorkerRecentEvent) {
225			liveEvents = [...liveEvents, event];
226		}
227	
228		function workerFrameFromProgressLine(line: string): WorkerRecentEvent | null {
229			const trimmed = line.trim();
230			if (!trimmed.startsWith('{')) return null;
231			try {
232				const raw = JSON.parse(trimmed) as Record<string, unknown>;
233				const kind = String(raw.kind ?? raw.type ?? '');
234				const payload =
235					raw.data && typeof raw.data === 'object' ? (raw.data as Record<string, unknown>) : raw;
236				if (kind === 'text_delta') {
237					const text = raw.text ?? payload.text ?? payload.delta;
238					return typeof text === 'string'
239						? { kind: 'text_delta', text, name: null, inputs: null, output: null }
240						: null;
241				}
242				if (kind === 'tool_call') {
243					return {
244						kind: 'tool_call',
245						text: null,
246						name: typeof payload.name === 'string' ? payload.name : null,
247						inputs: inputText(payload.inputs ?? payload.input),
248						output: typeof payload.output === 'string' ? payload.output : null
249					};
250				}
251			} catch {
252				return null;
253			}
254			return null;
255		}
256	
257		async function catchUpRecentEvents(workerId: string) {
258			catchingUp = true;
259			try {
260				const client = createClient(fetch);
261				const result = await client.request<{
262					worker: { recentEvents?: WorkerRecentEvent[] } | null;
263				}>(RECENT_EVENTS_QUERY, { id: workerId });
264				liveEvents = result.worker?.recentEvents ?? liveEvents;
265			} catch (err) {
266				console.error('[ddx] worker recentEvents catch-up failed:', err);
267			} finally {
268				catchingUp = false;
269				reconnecting = wsConnection.showBanner;
270			}
271		}
272	
273		const terminalPhases = new Set(['done', 'exited', 'stopped', 'failed', 'error', 'preserved']);
274	
275		const isTerminal = $derived(
276			data.worker?.state === 'done' ||
277				data.worker?.state === 'exited' ||
278				data.worker?.state === 'stopped' ||
279				data.worker?.state === 'failed' ||
280				data.worker?.state === 'error' ||
281				streamTerminal ||
282				Boolean(data.worker?.finishedAt)
283		);
284	
285		const completedAt = $derived(data.worker?.finishedAt ?? streamCompletedAt);
286	
287		const liveItems = $derived.by(() => {
288			const items: LiveItem[] = [];
289			for (const event of liveEvents) {
290				if (event.kind === 'text_delta' && event.text) {
291					const last = items.at(-1);
292					if (last?.type === 'text') {
293						last.text += event.text;
294					} else {
295						items.push({ type: 'text', text: event.text });
296					}
297				} else if (event.kind === 'tool_call') {
298					items.push({
299						type: 'tool_call',
300						event,
301						key: `${items.length}-${event.name ?? 'tool'}-${inputText(event.inputs).slice(0, 40)}`
302					});
303				}
304			}
305			return items;
306		});
307	</script>
